/**
 * station-uds-smoke.ts — micro-benchmark comparing a /health call to a
 * fat-station HTTP server vs a fat-station-uds UDS server.
 *
 * Run after booting one of each:
 *
 *   # HTTP (port 18001)
 *   ./target/release/fat-station --knot /tmp/qwen-coder-7b.knot \
 *      --port 18001 --role entry --layers 0..14 &
 *
 *   # UDS (/tmp/fs-smoke.sock)
 *   ./target/release/fat-station-uds --knot /tmp/qwen-coder-7b.knot \
 *      --sock /tmp/fs-smoke.sock --role entry --layers 0..14 &
 *
 *   bun open-source/gnosis/distributed-inference-host/__tests__/station-uds-smoke.ts \
 *      --http http://127.0.0.1:18001 \
 *      --uds  /tmp/fs-smoke.sock \
 *      --iterations 200
 */

import { StationUds } from '../src/station-uds';

interface Args {
  http: string;
  uds: string;
  iterations: number;
}

function parseArgs(argv: string[]): Args {
  const out: Args = { http: '', uds: '', iterations: 100 };
  for (let i = 0; i < argv.length; i++) {
    const a = argv[i];
    const v = argv[i + 1];
    if (a === '--http') out.http = v ?? '';
    else if (a === '--uds') out.uds = v ?? '';
    else if (a === '--iterations') out.iterations = Number.parseInt(v ?? '100', 10);
  }
  if (!out.http && !out.uds) {
    throw new Error('need at least one of --http <url> or --uds <socket-path>');
  }
  return out;
}

interface Stats {
  label: string;
  n: number;
  meanMs: number;
  medianMs: number;
  p95Ms: number;
  minMs: number;
  maxMs: number;
}

function summarize(label: string, samples: number[]): Stats {
  const sorted = [...samples].sort((a, b) => a - b);
  const sum = sorted.reduce((acc, x) => acc + x, 0);
  return {
    label,
    n: sorted.length,
    meanMs: sum / sorted.length,
    medianMs: sorted[Math.floor(sorted.length / 2)],
    p95Ms: sorted[Math.floor(sorted.length * 0.95)],
    minMs: sorted[0],
    maxMs: sorted[sorted.length - 1],
  };
}

function fmt(s: Stats): string {
  return `${s.label.padEnd(8)}  n=${s.n}  mean=${s.meanMs.toFixed(3)}ms  median=${s.medianMs.toFixed(3)}ms  p95=${s.p95Ms.toFixed(3)}ms  min=${s.minMs.toFixed(3)}ms  max=${s.maxMs.toFixed(3)}ms`;
}

async function benchHttp(url: string, iterations: number): Promise<Stats> {
  // Warmup
  await fetch(`${url}/health`).then((r) => r.text());
  const samples: number[] = [];
  for (let i = 0; i < iterations; i++) {
    const t0 = performance.now();
    const res = await fetch(`${url}/health`);
    await res.text();
    samples.push(performance.now() - t0);
  }
  return summarize('HTTP', samples);
}

async function benchUds(socketPath: string, iterations: number): Promise<Stats> {
  const station = new StationUds({ socketPath, startLayer: 0, endLayer: 14, role: 'entry' });
  // Warmup
  await station.health();
  const samples: number[] = [];
  for (let i = 0; i < iterations; i++) {
    const t0 = performance.now();
    await station.health();
    samples.push(performance.now() - t0);
  }
  return summarize('UDS', samples);
}

async function main(): Promise<void> {
  const args = parseArgs(process.argv.slice(2));
  console.log(`[smoke] iterations=${args.iterations}`);
  console.log(`[smoke] http=${args.http || '(skipped)'}`);
  console.log(`[smoke] uds =${args.uds || '(skipped)'}`);
  console.log('');

  const results: Stats[] = [];
  if (args.http) results.push(await benchHttp(args.http, args.iterations));
  if (args.uds) results.push(await benchUds(args.uds, args.iterations));

  console.log('=== /health latency ===');
  for (const s of results) console.log(fmt(s));

  if (results.length === 2) {
    const [http, uds] = results;
    const speedup = http.medianMs / uds.medianMs;
    console.log('');
    console.log(`UDS median is ${speedup.toFixed(2)}x faster than HTTP median`);
    console.log(`UDS mean   is ${(http.meanMs / uds.meanMs).toFixed(2)}x faster than HTTP mean`);
  }
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
